// Settings file path
static wchar_t g_settings_dir[MAX_PATH] = L"";
static wchar_t g_recent_file[MAX_PATH] = L"";

// Initialize settings directory
bool settings_init() {
    // Get AppData path
    wchar_t appdata[MAX_PATH];
    if (FAILED(SHGetFolderPathW(nullptr, CSIDL_APPDATA, nullptr, 0, appdata))) {
        return false;
    }

    // Build GitSmarter settings directory path
    swprintf_s(g_settings_dir, L"%s\\GitSmarter", appdata);

    // Create directory if it doesn't exist
    CreateDirectoryW(g_settings_dir, nullptr);

    // Build recent.json path
    swprintf_s(g_recent_file, L"%s\\recent.json", g_settings_dir);

    return true;
}

// Skip whitespace in JSON
static const char* skip_ws(const char* p) {
    while (*p && (*p == ' ' || *p == '\t' || *p == '\n' || *p == '\r')) p++;
    return p;
}

// Parse a JSON string value (assumes p points to opening quote)
static const char* parse_string(const char* p, wchar_t* out, size_t out_size) {
    if (*p != '"') return nullptr;
    p++; // skip opening quote

    size_t i = 0;
    while (*p && *p != '"' && i < out_size - 1) {
        if (*p == '\\' && *(p + 1)) {
            p++;
            switch (*p) {
                case 'n': out[i++] = L'\n'; break;
                case 't': out[i++] = L'\t'; break;
                case 'r': out[i++] = L'\r'; break;
                case '\\': out[i++] = L'\\'; break;
                case '"': out[i++] = L'"'; break;
                default: out[i++] = (wchar_t)*p; break;
            }
        } else {
            out[i++] = (wchar_t)*p;
        }
        p++;
    }
    out[i] = L'\0';

    // Validate closing quote exists (prevent reading beyond string end)
    if (*p != '"') return nullptr;
    p++; // skip closing quote
    return p;
}

// Parse a JSON number
static const char* parse_number(const char* p, int64_t* out) {
    *out = 0;
    bool negative = false;
    if (*p == '-') {
        negative = true;
        p++;
    }

    // Validate at least one digit exists
    if (*p < '0' || *p > '9') return nullptr;

    // Parse with overflow protection
    int64_t result = 0;
    while (*p >= '0' && *p <= '9') {
        int64_t digit = *p - '0';
        // Check for overflow before multiplying
        if (result > (INT64_MAX - digit) / 10) {
            // Truncate to max/min value and continue parsing
            result = negative ? INT64_MIN : INT64_MAX;
            while (*p >= '0' && *p <= '9') p++;
            *out = result;
            return p;
        }
        result = result * 10 + digit;
        p++;
    }
    *out = negative ? -result : result;
    return p;
}

// Load recent repositories from JSON file
bool settings_load_recent_repos(RecentRepository* repos, size_t* count, size_t max_count) {
    if (!repos || !count || max_count == 0) return false;
    *count = 0;

    if (g_recent_file[0] == L'\0') {
        if (!settings_init()) return false;
    }

    // Read file
    FILE* f = nullptr;
    if (_wfopen_s(&f, g_recent_file, L"rb") != 0 || !f) {
        return false;
    }

    fseek(f, 0, SEEK_END);
    long size = ftell(f);
    fseek(f, 0, SEEK_SET);

    if (size <= 0 || size > 1024 * 1024) { // Max 1MB
        fclose(f);
        return false;
    }

    char* buffer = new char[size + 1];
    size_t read = fread(buffer, 1, size, f);
    buffer[read] = '\0';
    fclose(f);

    // Simple JSON parsing for our specific format
    // {"recent":[{"path":"...","last_opened":123},...]}
    const char* p = buffer;
    p = skip_ws(p);

    if (*p != '{') {
        delete[] buffer;
        return false;
    }
    p++;

    // Find "recent" key
    p = skip_ws(p);
    while (*p && *p != ']' && *count < max_count) {
        // Look for array start
        if (*p == '[') {
            p++;
            p = skip_ws(p);

            // Parse array items
            while (*p && *p != ']' && *count < max_count) {
                if (*p == '{') {
                    p++;
                    RecentRepository* repo = &repos[*count];
                    memset(repo, 0, sizeof(RecentRepository));

                    // Parse object properties
                    while (*p && *p != '}') {
                        p = skip_ws(p);
                        if (*p == '"') {
                            wchar_t key[64] = L"";
                            p = parse_string(p, key, 64);
                            p = skip_ws(p);
                            if (*p == ':') p++;
                            p = skip_ws(p);

                            if (wcscmp(key, L"path") == 0) {
                                p = parse_string(p, repo->path, Git::MAX_PATH_LEN);
                            } else if (wcscmp(key, L"last_opened") == 0) {
                                p = parse_number(p, &repo->last_opened);
                            }
                        }
                        p = skip_ws(p);
                        if (*p == ',') p++;
                    }

                    // Extract name from path
                    if (repo->path[0]) {
                        const wchar_t* last_sep = wcsrchr(repo->path, L'\\');
                        if (!last_sep) last_sep = wcsrchr(repo->path, L'/');
                        if (last_sep) {
                            // _TRUNCATE form avoids invalid-parameter handler abort on long names.
                            wcsncpy_s(repo->name, _countof(repo->name), last_sep + 1, _TRUNCATE);
                        } else {
                            wcsncpy_s(repo->name, _countof(repo->name), repo->path, _TRUNCATE);
                        }
                        (*count)++;
                    }

                    if (*p == '}') p++;
                }
                p = skip_ws(p);
                if (*p == ',') p++;
                p = skip_ws(p);
            }
        }
        p++;
    }

    delete[] buffer;
    return true;
}

// Escape a string for JSON output
static void write_escaped_string(FILE* f, const wchar_t* str) {
    fputc('"', f);
    while (*str) {
        switch (*str) {
            case L'\\': fputs("\\\\", f); break;
            case L'"':  fputs("\\\"", f); break;
            case L'\n': fputs("\\n", f); break;
            case L'\r': fputs("\\r", f); break;
            case L'\t': fputs("\\t", f); break;
            default:
                if (*str < 128) {
                    fputc((char)*str, f);
                } else {
                    // Write UTF-8 encoding for non-ASCII
                    char utf8[8];
                    int len = WideCharToMultiByte(CP_UTF8, 0, str, 1, utf8, sizeof(utf8), nullptr, nullptr);
                    fwrite(utf8, 1, len, f);
                }
                break;
        }
        str++;
    }
    fputc('"', f);
}

// Save recent repositories to JSON file
bool settings_save_recent_repos(const RecentRepository* repos, size_t count) {
    if (g_recent_file[0] == L'\0') {
        if (!settings_init()) return false;
    }

    FILE* f = nullptr;
    if (_wfopen_s(&f, g_recent_file, L"wb") != 0 || !f) {
        return false;
    }

    fputs("{\n  \"recent\": [\n", f);

    for (size_t i = 0; i < count; i++) {
        fputs("    {\"path\": ", f);
        write_escaped_string(f, repos[i].path);
        fprintf(f, ", \"last_opened\": %lld}", repos[i].last_opened);
        if (i < count - 1) fputc(',', f);
        fputc('\n', f);
    }

    fputs("  ]\n}\n", f);
    fclose(f);
    return true;
}

// Add or update a recent repository (moves to top if exists)
void settings_add_recent_repo(RecentRepository* repos, size_t* count, size_t max_count, const wchar_t* path) {
    // Check if already exists
    for (size_t i = 0; i < *count; i++) {
        if (_wcsicmp(repos[i].path, path) == 0) {
            // Move to front
            RecentRepository temp = repos[i];
            for (size_t j = i; j > 0; j--) {
                repos[j] = repos[j - 1];
            }
            repos[0] = temp;
            repos[0].last_opened = (int64_t)time(nullptr);
            return;
        }
    }

    // Shift existing entries down
    if (*count >= max_count) {
        *count = max_count - 1;
    }
    for (size_t i = *count; i > 0; i--) {
        repos[i] = repos[i - 1];
    }

    // Add new entry at front (use truncating copy to avoid invalid-parameter handler
    // abort on long paths).
    wcsncpy_s(repos[0].path, _countof(repos[0].path), path, _TRUNCATE);

    // Extract name from path
    const wchar_t* last_sep = wcsrchr(path, L'\\');
    if (!last_sep) last_sep = wcsrchr(path, L'/');
    if (last_sep) {
        wcsncpy_s(repos[0].name, _countof(repos[0].name), last_sep + 1, _TRUNCATE);
    } else {
        wcsncpy_s(repos[0].name, _countof(repos[0].name), path, _TRUNCATE);
    }

    repos[0].last_opened = (int64_t)time(nullptr);
    (*count)++;
}

// Remove a recent repository by index
void settings_remove_recent_repo(RecentRepository* repos, size_t* count, size_t index) {
    if (index >= *count) return;

    for (size_t i = index; i < *count - 1; i++) {
        repos[i] = repos[i + 1];
    }
    (*count)--;
}

// Global app settings instance
static AppSettings g_app_settings = {};

// Load application settings from settings.json
bool settings_load_app_settings(AppSettings* settings) {
    if (!settings) return false;

    wchar_t settings_path[MAX_PATH];
    swprintf_s(settings_path, L"%s\\settings.json", g_settings_dir);

    FILE* f = nullptr;
    if (_wfopen_s(&f, settings_path, L"rb") != 0 || !f) {
        // File doesn't exist, use defaults
        *settings = AppSettings();
        return false;
    }

    // Read file
    fseek(f, 0, SEEK_END);
    long file_size = ftell(f);
    fseek(f, 0, SEEK_SET);

    if (file_size <= 0 || file_size > 1024 * 1024) {
        fclose(f);
        return false;
    }

    char* buffer = (char*)malloc(file_size + 1);
    if (!buffer) {
        fclose(f);
        return false;
    }

    size_t bytes_read = fread(buffer, 1, file_size, f);
    buffer[bytes_read] = '\0';
    fclose(f);

    // Parse JSON (simple parsing for our specific format)
    const char* p = buffer;
    p = skip_ws(p);
    if (*p != '{') {
        free(buffer);
        return false;
    }
    p++;

    // Reset settings to defaults
    *settings = AppSettings();

    // Parse fields
    while (*p) {
        p = skip_ws(p);
        if (*p == '}') break;
        if (*p == ',') p++;
        p = skip_ws(p);
        if (*p == '}') break;
        if (*p != '"') break;

        // Parse key
        p++;
        char key[64];
        size_t key_len = 0;
        while (*p && *p != '"' && key_len < 63) {
            key[key_len++] = *p++;
        }
        key[key_len] = '\0';
        if (*p != '"') break;
        p++;

        p = skip_ws(p);
        if (*p != ':') break;
        p++;
        p = skip_ws(p);

        // Parse value based on key
        if (strcmp(key, "sidebar_width") == 0) {
            settings->sidebar_width = (float)atof(p);
        } else if (strcmp(key, "branch_section_split") == 0) {
            settings->branch_section_split = (float)atof(p);
        } else if (strcmp(key, "diff_side_by_side") == 0) {
            // Parse boolean
            p = skip_ws(p);
            settings->diff_side_by_side = (strncmp(p, "true", 4) == 0);
        } else if (strcmp(key, "diff_split_ratio") == 0) {
            settings->diff_split_ratio = (float)atof(p);
        } else if (strcmp(key, "clone_cache_size_gb") == 0) {
            settings->clone_cache_size_gb = atoi(p);
        } else if (strcmp(key, "log_category_mask") == 0) {
            settings->log_category_mask = (uint32_t)strtoul(p, nullptr, 10);
        } else if (strcmp(key, "log_subsystem_mask") == 0) {
            settings->log_subsystem_mask = (uint32_t)strtoul(p, nullptr, 10);
        } else if (strcmp(key, "log_file_enabled") == 0) {
            p = skip_ws(p);
            settings->log_file_enabled = (strncmp(p, "true", 4) == 0);
        } else if (strcmp(key, "log_telemetry_enabled") == 0) {
            p = skip_ws(p);
            settings->log_telemetry_enabled = (strncmp(p, "true", 4) == 0);
        }

        // Skip to next field
        while (*p && *p != ',' && *p != '}') p++;
    }

    free(buffer);
    g_app_settings = *settings;
    return true;
}

// Save application settings to settings.json
bool settings_save_app_settings(const AppSettings* settings) {
    if (!settings) return false;

    wchar_t settings_path[MAX_PATH];
    swprintf_s(settings_path, L"%s\\settings.json", g_settings_dir);

    FILE* f = nullptr;
    if (_wfopen_s(&f, settings_path, L"wb") != 0 || !f) {
        return false;
    }

    // Write JSON
    fprintf(f, "{\n");
    fprintf(f, "  \"sidebar_width\": %.1f,\n", settings->sidebar_width);
    fprintf(f, "  \"branch_section_split\": %.3f,\n", settings->branch_section_split);
    fprintf(f, "  \"diff_side_by_side\": %s,\n", settings->diff_side_by_side ? "true" : "false");
    fprintf(f, "  \"diff_split_ratio\": %.3f,\n", settings->diff_split_ratio);
    fprintf(f, "  \"clone_cache_size_gb\": %d,\n", settings->clone_cache_size_gb);
    fprintf(f, "  \"log_category_mask\": %u,\n", settings->log_category_mask);
    fprintf(f, "  \"log_subsystem_mask\": %u,\n", settings->log_subsystem_mask);
    fprintf(f, "  \"log_file_enabled\": %s,\n", settings->log_file_enabled ? "true" : "false");
    fprintf(f, "  \"log_telemetry_enabled\": %s\n", settings->log_telemetry_enabled ? "true" : "false");
    fprintf(f, "}\n");

    fclose(f);
    g_app_settings = *settings;
    return true;
}

// Get branch expand state for a repository
const char* settings_get_branch_expand_state(const wchar_t* repo_path) {
    for (size_t i = 0; i < g_app_settings.repo_settings_count; i++) {
        if (wcscmp(g_app_settings.repo_settings[i].repo_path, repo_path) == 0) {
            return g_app_settings.repo_settings[i].branch_expand_state;
        }
    }
    return "";  // Not found
}

// Set branch expand state for a repository
void settings_set_branch_expand_state(const wchar_t* repo_path, const char* state) {
    if (!repo_path || !state) return;

    // Find or create entry
    for (size_t i = 0; i < g_app_settings.repo_settings_count; i++) {
        if (wcscmp(g_app_settings.repo_settings[i].repo_path, repo_path) == 0) {
            strncpy_s(g_app_settings.repo_settings[i].branch_expand_state,
                      sizeof(g_app_settings.repo_settings[i].branch_expand_state),
                      state, _TRUNCATE);
            return;
        }
    }

    // Add new entry (evict oldest if full)
    if (g_app_settings.repo_settings_count >= 10) {
        // Shift array left
        for (size_t i = 0; i < 9; i++) {
            g_app_settings.repo_settings[i] = g_app_settings.repo_settings[i + 1];
        }
        g_app_settings.repo_settings_count = 9;
    }

    AppSettings::RepoSettings* entry =
        &g_app_settings.repo_settings[g_app_settings.repo_settings_count++];
    wcsncpy_s(entry->repo_path, _countof(entry->repo_path), repo_path, _TRUNCATE);
    strncpy_s(entry->branch_expand_state, sizeof(entry->branch_expand_state), state, _TRUNCATE);
}

