bool settings_save_window_placement(HWND hwnd) {
    if (!g_settings_dir[0]) return false;

    wchar_t path[MAX_PATH];
    swprintf_s(path, MAX_PATH, L"%s\\window.dat", g_settings_dir);

    WINDOWPLACEMENT wp = { sizeof(wp) };
    if (!GetWindowPlacement(hwnd, &wp)) return false;

    FILE* f = nullptr;
    if (_wfopen_s(&f, path, L"wb") != 0 || !f) return false;

    bool ok = fwrite(&wp, sizeof(wp), 1, f) == 1;
    fclose(f);
    return ok;
}

// Get clone cache size from settings (in GB, 0 = auto)
int settings_get_clone_cache_size_gb() {
    return g_app_settings.clone_cache_size_gb;
}

bool settings_load_window_placement(WINDOWPLACEMENT* wp) {
    if (!g_settings_dir[0] || !wp) return false;

    wchar_t path[MAX_PATH];
    swprintf_s(path, MAX_PATH, L"%s\\window.dat", g_settings_dir);

    FILE* f = nullptr;
    if (_wfopen_s(&f, path, L"rb") != 0 || !f) return false;

    bool ok = fread(wp, sizeof(WINDOWPLACEMENT), 1, f) == 1;
    fclose(f);

    // Validate structure size matches
    if (ok && wp->length != sizeof(WINDOWPLACEMENT)) {
        ok = false;
    }

    return ok;
}
